class Solution:
    def maxDotProduct(self, nums1: list, nums2: list) -> int:
        m, n = len(nums1), len(nums2)
        NEG = float('-inf')
        dp = [[NEG] * (n + 1) for _ in range(m + 1)]
        for i in range(1, m + 1):
            for j in range(1, n + 1):
                pair = nums1[i-1] * nums2[j-1]
                best_prev = max(0, dp[i-1][j-1]) if dp[i-1][j-1] != NEG else 0
                candidates = [pair + best_prev]
                if dp[i-1][j] != NEG: candidates.append(dp[i-1][j])
                if dp[i][j-1] != NEG: candidates.append(dp[i][j-1])
                dp[i][j] = max(candidates)
        return dp[m][n]

