var maxDotProduct = function(nums1, nums2) {
    const m = nums1.length, n = nums2.length;
    const NEG = -Infinity;
    const dp = Array.from({length: m+1}, () => new Array(n+1).fill(NEG));
    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            const pair = nums1[i-1] * nums2[j-1];
            const bestPrev = dp[i-1][j-1] === NEG ? 0 : Math.max(0, dp[i-1][j-1]);
            let best = pair + bestPrev;
            if (dp[i-1][j] !== NEG && dp[i-1][j] > best) best = dp[i-1][j];
            if (dp[i][j-1] !== NEG && dp[i][j-1] > best) best = dp[i][j-1];
            dp[i][j] = best;
        }
    }
    return dp[m][n];
};
